const expectedToken = 'REPLACE_WITH_RABBIT_TOKEN';
const allowedAreas = ['Salud', 'Trabajo', 'Finanzas', 'Relaciones', 'Casa', 'Aprendizaje', 'Ideas', 'Personal'];

function parsePayload(input) {
  const direct = input.payload ?? input.body?.payload ?? input.body ?? input;

  if (typeof direct === 'string') {
    try {
      return JSON.parse(direct);
    } catch (error) {
      return { message: direct };
    }
  }

  return direct || {};
}

function cleanArea(value) {
  const area = String(value || '').trim();
  return allowedAreas.includes(area) ? area : 'Ideas';
}

const payload = parsePayload($json);
const token = String(payload.token || payload.apiKey || payload.key || '');
const tokenConfigured = expectedToken && !expectedToken.startsWith('REPLACE_WITH_');
const valid = Boolean(tokenConfigured && token === expectedToken);
const audioBase64 = String(payload.audioBase64 || payload.audio || '').trim();
const message = String(payload.message || payload.text || payload.transcript || '').trim();
const action = String(payload.action || (audioBase64 ? 'instruct' : 'list')).trim();
const now = new Date().toISOString();

return [{
  json: {
    valid,
    revoked: !valid,
    status: valid ? 'ok' : 'revoked',
    reply: valid ? 'Procesando Drop Board.' : 'Token revocado o invalido.',
    action,
    area: cleanArea(payload.area),
    message,
    audioBase64,
    audioMimeType: String(payload.audioMimeType || 'audio/webm'),
    audioName: String(payload.audioName || 'drop-board-r1.webm'),
    sessionId: String(payload.sessionId || ''),
    source: String(payload.source || 'rabbit-r1-drop-board'),
    sentAt: payload.sentAt || now,
    receivedAt: now
  }
}];

function withoutAudio(input) {
  const { audioBase64, ...rest } = input;
  return rest;
}

function extensionFor(mimeType) {
  const clean = String(mimeType || '').split(';')[0].trim().toLowerCase();
  if (clean.includes('mp4') || clean.includes('m4a')) return 'm4a';
  if (clean.includes('ogg')) return 'ogg';
  if (clean.includes('wav')) return 'wav';
  if (clean.includes('mpeg') || clean.includes('mp3')) return 'mp3';
  return 'webm';
}

const base64 = String($json.audioBase64 || '').replace(/^data:.*?;base64,/, '');
const rawMimeType = String($json.audioMimeType || 'audio/webm');
const mimeType = rawMimeType.split(';')[0].trim() || 'audio/webm';
const extension = extensionFor(mimeType);
const fileName = String($json.audioName || `drop-board-r1.${extension}`).replace(/[^a-z0-9._-]/gi, '_');
const safeName = fileName.includes('.') ? fileName : `drop-board-r1.${extension}`;

if (!base64) {
  const existingMessage = String($json.message || '').trim();
  return [{
    json: {
      ...withoutAudio($json),
      message: existingMessage,
      transcript: existingMessage,
      transcriptionError: existingMessage ? '' : 'empty_audio',
      transcriptionModel: 'whisper-1'
    }
  }];
}

return [{
  json: {
    ...withoutAudio($json),
    message: '',
    transcript: '',
    transcriptionModel: 'whisper-1'
  },
  binary: {
    audio: {
      data: base64,
      mimeType,
      fileName: safeName,
      fileExtension: extension
    }
  }
}];

let source = {};
try { source = $('Prepare audio binary').first().json || {}; } catch (error) {}

const transcript = String($json.text || $json.transcript || source.transcript || source.message || '').trim();
const errorMessage = $json.error?.message || (!transcript ? $json.message : '') || source.transcriptionError || '';

return [{
  json: {
    ...source,
    ...$json,
    message: transcript,
    transcript,
    transcriptionError: transcript ? '' : (errorMessage || 'empty_transcript'),
    transcriptionModel: 'whisper-1'
  }
}];

const openAiApiKey = 'REPLACE_WITH_OPENAI_API_KEY';
const allowedAreas = ['Salud', 'Trabajo', 'Finanzas', 'Relaciones', 'Casa', 'Aprendizaje', 'Ideas', 'Personal'];
const selectedArea = allowedAreas.includes(String($json.area || '').trim()) ? String($json.area).trim() : 'Ideas';
const message = String($json.message || '').trim();

function fallback(reason = '') {
  const title = message ? message.slice(0, 80) : 'Drop Board';
  return [{
    json: {
      ...$json,
      shouldCreate: Boolean(message),
      titulo: title,
      area: selectedArea,
      observaciones: message || 'Sin instruccion recibida.',
      boardReply: message ? `Anotado en ${selectedArea}.` : 'No he recibido instruccion.',
      aiModel: 'fallback',
      aiFallbackReason: reason
    }
  }];
}

if (!message) return fallback('empty_message');
if (!openAiApiKey || openAiApiKey.startsWith('REPLACE_WITH_')) return fallback('missing_openai_key');

const system = [
  'Eres Drop Board, un asistente que opera una base de datos de Notion llamada Mind Drop.',
  'Recibes instrucciones de voz desde Rabbit R1.',
  'Tu tarea V0 es convertir la instruccion en un nuevo drop util, o una nota de trabajo accionable.',
  'Devuelve solo JSON valido.',
  'Campos: shouldCreate, titulo, area, observaciones, reply.',
  `area debe ser exactamente una de: ${allowedAreas.join(', ')}.`,
  'Si el usuario dice un area explicita, respetala. Si no, usa el area seleccionada como contexto.',
  'titulo maximo 80 caracteres. observaciones en 1-3 frases. reply breve para el Rabbit.'
].join(' ');

try {
  const data = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.openai.com/v1/chat/completions',
    headers: {
      Authorization: `Bearer ${openAiApiKey}`,
      'Content-Type': 'application/json'
    },
    body: {
      model: 'gpt-4.1-nano',
      temperature: 0.1,
      response_format: { type: 'json_object' },
      messages: [
        { role: 'system', content: system },
        { role: 'user', content: JSON.stringify({ selectedArea, instruction: message }) }
      ]
    },
    json: true
  });

  const parsed = JSON.parse(data.choices?.[0]?.message?.content || '{}');
  const area = allowedAreas.includes(String(parsed.area || '').trim()) ? String(parsed.area).trim() : selectedArea;
  const titulo = String(parsed.titulo || parsed.title || message).trim().slice(0, 80) || 'Drop Board';
  const observaciones = String(parsed.observaciones || parsed.notes || parsed.observation || message).trim();

  return [{
    json: {
      ...$json,
      shouldCreate: parsed.shouldCreate !== false,
      titulo,
      area,
      observaciones,
      boardReply: String(parsed.reply || `Actualizado ${area}.`).trim(),
      aiModel: 'gpt-4.1-nano'
    }
  }];
} catch (error) {
  return fallback(error.message || 'openai_error');
}

const allowedAreas = ['Salud', 'Trabajo', 'Finanzas', 'Relaciones', 'Casa', 'Aprendizaje', 'Ideas', 'Personal'];

function getSource() {
  try { return $('AI Action').first().json; } catch (error) {}
  try { return $('Validate Rabbit token').first().json; } catch (error) {}
  return {};
}

function text(value) {
  return String(value || '').trim();
}

function rowFrom(item) {
  const json = item.json || {};
  const title = text(json.property_titulo || json.Titulo || json.titulo || json.title || json.Name || json.name || 'Drop');
  const area = text(json.property_area || json.Area || json.area || json['Area|select'] || 'Personal');
  const observations = text(json.property_observaciones || json.Observaciones || json.observaciones || json['Observaciones|rich_text'] || json.notes || '');
  return {
    id: text(json.id || json.pageId || ''),
    title,
    area: allowedAreas.includes(area) ? area : 'Personal',
    observations,
    updatedAt: text(json.last_edited_time || json.updatedAt || json.created_time || '')
  };
}

const source = getSource();
const selectedArea = allowedAreas.includes(text(source.area)) ? text(source.area) : 'Ideas';
const rows = $input.all().map(rowFrom);
const filtered = rows
  .filter((row) => row.area === selectedArea)
  .sort((a, b) => String(b.updatedAt).localeCompare(String(a.updatedAt)))
  .slice(0, 12);

return [{
  json: {
    ok: true,
    status: 'ok',
    action: source.action || 'list',
    area: selectedArea,
    types: allowedAreas,
    items: filtered,
    reply: source.boardReply || `Drops de ${selectedArea}: ${filtered.length}`,
    transcript: source.transcript || source.message || ''
  }
}];

return [{
  json: {
    ok: false,
    revoked: true,
    status: 'revoked',
    reply: 'Token revocado o invalido.'
  }
}];
